t.script:
// ── Helpers ─────────────────────────────────────────────────────
const SC = {
  'نشطة':'#27AE60','نشط':'#27AE60','مرحّل':'#27AE60','مكتمل':'#27AE60','ساري':'#27AE60',
  'مسودة':'#9BAAB8','منتهية':'#9BAAB8','ملغي':'#9BAAB8',
  'إخطار الترسية':'#C9A84C','تمت المقارنة':'#C9A84C','معتمد':'#C9A84C','تسجيل العروض':'#C9A84C',
  'مظاريف مالية مفتوحة':'#F39C12','مظاريف فنية مفتوحة':'#F39C12','الجلسة مفتوحة':'#F39C12','جاري الجرد':'#F39C12',
  'أمر شراء صادر':'#2196F3','محوّل':'#2196F3',
  'مرفوض':'#E74C3C','متأخرة':'#E74C3C','متأخر':'#E74C3C','مُرتجعة':'#9BAAB8',
};
const bdg = s => { const c=SC[s]||'#9BAAB8'; return `${s}`; };
const fmt = n => { if(!n)return'0'; if(n>=1e6)return(n/1e6).toFixed(1)+'م'; if(n>=1e3)return(n/1e3).toFixed(0)+'ك'; return n.toLocaleString(); };

// ── Data store ───────────────────────────────────────────────────
let D = null;

// ── Fetch from Odoo RPC ──────────────────────────────────────────
async function fetchData() {
  try {
    const res = await fetch('/portsaid/dashboard/data', {
      method:'POST',
      headers:{'Content-Type':'application/json','X-Requested-With':'XMLHttpRequest'},
      body: JSON.stringify({jsonrpc:'2.0',method:'call',id:1,params:{}})
    });
    const json = await res.json();
    D = json.result;
    initDashboard();
  } catch(e) {
    document.getElementById('ps-loading').innerHTML =
      '
خطأ في تحميل البيانات
'+e.message+'';
  }
}

// ── Initialize ───────────────────────────────────────────────────
function initDashboard() {
  if(!D) return;
  document.getElementById('ps-loading').style.display = 'none';
  document.getElementById('ps-pages').style.display   = 'block';

  // Header stats
  document.getElementById('hd-ops').textContent = D.meta.total_ops || 0;
  document.getElementById('hd-val').textContent = fmt(D.adjudication.total_estimated || 0) + ' ج.م';
  document.getElementById('hd-alr').textContent = (D.alerts||[]).length;

  // Nav badges
  document.getElementById('nb-adj').textContent = D.adjudication.total || '';
  document.getElementById('nb-prm').textContent = D.permits.total || '';
  document.getElementById('nb-cus').textContent = D.custody.active || '';
  document.getElementById('nb-auc').textContent = (D.auction.by_state.session_open||0) + (D.auction.by_state.bidding||0) || '';
  document.getElementById('nb-alr').textContent = (D.alerts||[]).length || '';

  renderPage('overview');

  // Nav click
  document.querySelectorAll('.pnb').forEach(b => {
    b.addEventListener('click', () => {
      document.querySelectorAll('.pnb').forEach(x => x.classList.remove('active'));
      b.classList.add('active');
      renderPage(b.dataset.page);
    });
  });

  // Drill close on overlay click
  document.getElementById('drill-ov').addEventListener('click', e => {
    if(e.target === document.getElementById('drill-ov')) closeDrill();
  });
}

// ── Page renderer ────────────────────────────────────────────────
function renderPage(pg) {
  const el = document.getElementById('ps-pages');
  el.innerHTML = buildPage(pg);
  setTimeout(() => animBars(el), 60);
}

function buildPage(pg) {
  switch(pg) {
    case 'overview':   return pgOverview();
    case 'contracts':  return pgContracts();
    case 'warehouse':  return pgWarehouse();
    case 'custody':    return pgCustody();
    case 'auction':    return pgAuction();
    case 'alerts':     return pgAlerts();
    default:           return pgOverview();
  }
}

// ── Component builders ───────────────────────────────────────────
function kpi(icon,val,label,color,sub,drill) {
  const d = drill ? `onclick="openDrill('${drill}')"` : '';
  return `


${icon}

${val}

${label}
    ${sub?`
${sub}`:''}
    ${drill?'
تفاصيل ↗':''}
  `;
}

function sbars(data) {
  const tot = data.reduce((s,d)=>s+(d.n||0),0)||1;
  return data.map(d => {
    const w = (d.n||0)/tot*100;
    const p = Math.round(w);
    return `


${d.l}




${d.n||0}

${p}%
    `;
  }).join('');
}

function barchart(data) {
  const max = Math.max(...data.map(d=>d.v||0),1);
  return `
${data.map(d=>{
    const h = Math.round((d.v||0)/max*75);
    return `


${d.v}



${d.l}
    `;
  }).join('')}`;
}

function donut(segs) {
  const tot = segs.reduce((s,d)=>s+(d.v||0),0)||1;
  const r=38, circ=2*Math.PI*r; let off=0;
  const circles = segs.map(s=>{
    const len=circ*(s.v||0)/tot, rot=off; off+=len;
    return ``;
  });
  const pct = Math.round((segs[0].v||0)/tot*100);
  return `





        ${circles.join('')}




${pct}%

${segs[0].l}



${segs.map(s=>`




${s.l}

${s.v}
    `).join('')}
  `;
}

function gauge(title,val,pct,color,sub) {
  const fill = Math.min(pct||0,100)*1.57;
  return `


${title}





${val}

${sub}
  `;
}

function trow(cols) { return `
${cols.map(c=>`${c}`).join('')}`; }
function thead(cols) { return `
${cols.map(c=>`${c}`).join('')}`; }

// ── Pages ────────────────────────────────────────────────────────
function pgOverview() {
  const c=D.committees, a=D.adjudication, p=D.permits, s=D.stocktaking, cu=D.custody, au=D.auction;
  return `


مؤشرات الأداء الرئيسية


      ${kpi('👥',c.active,'لجنة نشطة','#C9A84C',`${c.draft} مسودة`,'committees')}
      ${kpi('⚖️',a.by_state.awarded+a.by_state.po_created,'في مرحلة الترسية','#27AE60',`${a.total} إجمالي ملفات`,'adjudication')}
      ${kpi('📦',p.total,'إذن إضافة','#27A99A',`${p.posted} مرحّل`,'permits')}
      ${kpi('🔑',cu.active,'عهدة نشطة','#2196F3',`⚠️ ${cu.overdue} متأخرة`,'custody')}
      ${kpi('📊',s.done,'جرد بانتظار الاعتماد','#E74C3C',`${s.validated} معتمد`,'stocktaking')}
      ${kpi('🏛️',(au.by_state.session_open||0)+(au.by_state.bidding||0),'مزاد نشط','#F39C12',`${au.lease.active} عقد إيجار`,'auctions')}





📋 مسار التعاقدات
        ${sbars([
          {l:'مسودة',n:a.by_state.draft,c:'#9BAAB8'},
          {l:'مظاريف فنية',n:a.by_state.technical_open,c:'#F39C12'},
          {l:'مظاريف مالية',n:a.by_state.financial_open,c:'#C9A84C'},
          {l:'تمت المقارنة',n:a.by_state.adjudicated,c:'#2196F3'},
          {l:'إخطار الترسية',n:a.by_state.awarded,c:'#27AE60'},
          {l:'أمر شراء',n:a.by_state.po_created,c:'#1565C0'},
        ])}



📦 نتائج الفحص والاستلام
        ${donut([
          {c:'#27A99A',l:'مكتمل مطابق',v:p.inspection.done},
          {c:'#C9A84C',l:'مطابق مع تحفظ',v:Math.max(0,Math.round(p.inspection.done*.1))},
          {c:'#E74C3C',l:'مرفوض',v:p.inspection.rejected},
        ])}






📈 العمليات الشهرية
        ${barchart(D.monthly.map((m,i)=>({l:m.label,v:m.count,c:i===D.monthly.length-1?'#C9A84C':i===D.monthly.length-2?'#27A99A':'#2E4B6E'})))}



🔑 توزيع العهد
        ${sbars([
          {l:'نشطة',n:cu.active,c:'#27AE60'},
          {l:'محوّلة',n:cu.transferred,c:'#2196F3'},
          {l:'متأخرة',n:cu.overdue,c:'#E74C3C'},
          {l:'مُرتجعة',n:cu.returned,c:'#9BAAB8'},
        ])}


  `;
}

function pgContracts() {
  const a=D.adjudication, c=D.committees;
  const tLabels={public:'مناقصة عامة',local:'مناقصة محلية',limited:'مناقصة محدودة',
    negotiation:'ممارسة',direct_supply:'أمر مباشر',direct_private:'اتفاق مباشر'};
  return `


التعاقدات والمناقصات


      ${kpi('📝',c.total,'إجمالي اللجان','#C9A84C',`${c.active} نشطة`,'committees')}
      ${kpi('⚖️',a.total,'ملف بت','#27AE60',`${a.by_state.awarded} ترسية`,'adjudication')}
      ${kpi('💰',fmt(a.total_estimated),'قيمة تقديرية (ج.م)','#2196F3','')}
      ${kpi('📊',(a.saving_pct||0)+'%','نسبة التوفير','#F39C12','مقارنة بالتقديري')}





حالة ملفات البت
        ${sbars([
          {l:'مسودة',n:a.by_state.draft,c:'#9BAAB8'},
          {l:'مظاريف فنية مفتوحة',n:a.by_state.technical_open,c:'#F39C12'},
          {l:'مظاريف مالية مفتوحة',n:a.by_state.financial_open,c:'#FFCC99'},
          {l:'تمت المقارنة',n:a.by_state.adjudicated,c:'#C9A84C'},
          {l:'إخطار الترسية',n:a.by_state.awarded,c:'#27AE60'},
          {l:'أمر شراء صادر',n:a.by_state.po_created,c:'#1565C0'},
          {l:'ملغي',n:a.by_state.cancelled,c:'#E74C3C'},
        ])}



توزيع وسائل الطرح
        ${barchart(Object.entries(a.tender_types||{}).map(([k,v])=>({l:tLabels[k]||k,v,c:'#2196F3'})))}






آخر ملفات البت

        ${thead(['المرجع','العملية','وسيلة الطرح','الحالة','القيمة التقديرية','قيمة الترسية','المورد'])}
        ${(a.detail||[]).map(r=>trow([
          `${r.ref}`,
          r.name, r.tender, bdg(r.state),
          r.estimated?r.estimated.toLocaleString()+' ج.م':'—',
          r.awarded?`${r.awarded.toLocaleString()} ج.م`:'—',
          r.supplier,
        ])).join('')}


  `;
}

function pgWarehouse() {
  const p=D.permits, s=D.stocktaking;
  return `


المخازن والجرد


      ${kpi('📦',p.total,'إذن إضافة','#27A99A',`${p.posted} مرحّل`,'permits')}
      ${kpi('✅',p.posted,'مرحّل بنجاح','#27AE60',Math.round(p.posted/(p.total||1)*100)+'% قبول')}
      ${kpi('❌',p.cancelled,'مرفوض/ملغي','#E74C3C','يحتاج مراجعة')}
      ${kpi('🔍',s.total,'جلسة جرد','#C9A84C',`${s.done} بانتظار الاعتماد`,'stocktaking')}





نتائج محاضر الفحص
        ${sbars([
          {l:'مكتمل مطابق',n:p.inspection.done,c:'#27AE60'},
          {l:'قيد الفحص',n:p.inspection.draft,c:'#F39C12'},
          {l:'مرفوض',n:p.inspection.rejected,c:'#E74C3C'},
        ])}



جلسات الجرد — الحالة
        ${sbars([
          {l:'مسودة',n:s.draft,c:'#9BAAB8'},
          {l:'جاري الجرد',n:s.counting,c:'#F39C12'},
          {l:'منتهي',n:s.done,c:'#2196F3'},
          {l:'معتمد',n:s.validated,c:'#27AE60'},
        ])}




      ${gauge('نسبة الزيادة',s.surplus_pct+'%',s.surplus_pct,'#27AE60','أصناف زيادة')}
      ${gauge('نسبة العجز',s.deficit_pct+'%',s.deficit_pct,'#E74C3C','أصناف عجز')}



أذونات الإضافة
        ${donut([
          {c:'#27AE60',l:'مرحّل',v:p.posted},
          {c:'#F39C12',l:'مسودة',v:p.draft},
          {c:'#E74C3C',l:'ملغي',v:p.cancelled},
        ])}


  `;
}

function pgCustody() {
  const cu=D.custody;
  return `


إدارة العهد


      ${kpi('🔑',cu.active,'عهدة نشطة','#2196F3','','custody')}
      ${kpi('⚠️',cu.overdue,'متأخرة الاسترداد','#E74C3C','يجب المتابعة')}
      ${kpi('↩️',cu.returned,'مُرتجعة','#27AE60','إجمالي')}
      ${kpi('💎',fmt(cu.total_value),'قيمة العهد النشطة (ج.م)','#C9A84C','')}





توزيع العهد حسب الحالة
        ${sbars([
          {l:'نشطة',n:cu.active,c:'#27AE60'},
          {l:'محوّلة',n:cu.transferred,c:'#2196F3'},
          {l:'متأخرة',n:cu.overdue,c:'#E74C3C'},
          {l:'مُرتجعة',n:cu.returned,c:'#9BAAB8'},
        ])}



نوع العهد
        ${sbars([
          {l:'شخصية',n:cu.by_type.personal,c:'#2196F3'},
          {l:'مشتركة',n:cu.by_type.shared,c:'#27A99A'},
          {l:'منقولة',n:cu.by_type.transferred,c:'#C9A84C'},
        ])}






⚠️ العهد المتأخرة

        ${thead(['المرجع','الموظف','القيمة','تاريخ الاسترداد','الحالة'])}
        ${(cu.overdue_detail||[]).length?
          (cu.overdue_detail).map(r=>trow([
            `${r.ref}`,
            r.employee, r.value?r.value.toLocaleString()+' ج.م':'—',
            `${r.due}`, bdg('متأخرة'),
          ])).join('') :
          '
✅ لا توجد عهد متأخرة'
        }


  `;
}

function pgAuction() {
  const au=D.auction;
  return `


المزايدات والمزادات


      ${kpi('🏛️',(au.by_state.session_open||0)+(au.by_state.bidding||0),'مزاد نشط','#F39C12','','auctions')}
      ${kpi('🏆',au.by_state.done,'مزاد مكتمل','#27AE60','')}
      ${kpi('📃',au.lease.active,'عقد إيجار ساري','#2196F3',`${au.lease.expired} منتهي`)}
      ${kpi('💸',au.payments.overdue,'دفعة متأخرة','#E74C3C','مطلوب تحصيل')}





حالة طلبات المزاد
        ${sbars([
          {l:'مسودة',n:au.by_state.draft,c:'#9BAAB8'},
          {l:'الجلسة مفتوحة',n:au.by_state.session_open,c:'#F39C12'},
          {l:'تسجيل العروض',n:au.by_state.bidding,c:'#C9A84C'},
          {l:'تم الترسية',n:au.by_state.awarded,c:'#27AE60'},
          {l:'منتهي',n:au.by_state.done,c:'#2E4B6E'},
          {l:'ملغي',n:au.by_state.cancelled,c:'#E74C3C'},
        ])}



جدول سداد العقود
        ${sbars([
          {l:'قيد الانتظار',n:au.payments.pending,c:'#9BAAB8'},
          {l:'مدفوع جزئياً',n:au.payments.partial,c:'#F39C12'},
          {l:'مدفوع',n:au.payments.paid,c:'#27AE60'},
          {l:'متأخر',n:au.payments.overdue,c:'#E74C3C'},
        ])}






المزادات الجارية والمكتملة

        ${thead(['المرجع','الاسم','النوع','الحالة','القيمة التقديرية','مبلغ الترسية'])}
        ${(au.detail||[]).map(r=>trow([
          `${r.ref}`,
          r.name, r.type, bdg(r.state),
          r.estimated?r.estimated.toLocaleString()+' ج.م':'—',
          r.awarded?`${r.awarded.toLocaleString()} ج.م`:'—',
        ])).join('')}


  `;
}

function pgAlerts() {
  const clr={danger:'#E74C3C',warning:'#F39C12',info:'#2196F3'};
  const als=D.alerts||[];
  return `


التنبيهات العاجلة (${als.length})
    ${als.length?als.map(a=>`


${a.icon}



${a.title}

${a.desc}

    `).join(''):'
✅ لا توجد تنبيهات عاجلة'}
  `;
}

// ── Animations ───────────────────────────────────────────────────
function animBars(el) {
  el.querySelectorAll('.sbfill[data-w]').forEach(e => { e.style.width = e.dataset.w+'%'; });
  el.querySelectorAll('.pbf[data-h]').forEach(e  => { e.style.height = (parseInt(e.dataset.h)||4)+'px'; });
}

// ── Drill-down ───────────────────────────────────────────────────
const DRILLS = {
  committees: () => ({
    title:'👥 تفاصيل اللجان المشكّلة',
    kpis:[{v:D.committees.total,l:'إجمالي'},{v:D.committees.active,l:'نشطة'},{v:D.committees.draft,l:'مسودة'}],
    headers:['المرجع','الاسم','النوع','الحالة','الأعضاء','التاريخ'],
    rows:(D.committees.detail||[]).map(r=>[
      `${r.ref}`,
      r.name,r.type,bdg(r.state),r.members,r.date
    ]),
  }),
  adjudication: () => ({
    title:'⚖️ تفاصيل ملفات البت',
    kpis:[{v:D.adjudication.total,l:'إجمالي'},{v:fmt(D.adjudication.total_estimated),l:'قيمة تقديرية'},{v:(D.adjudication.saving_pct||0)+'%',l:'توفير'}],
    headers:['المرجع','العملية','الحالة','التقديري','الترسية','المورد'],
    rows:(D.adjudication.detail||[]).map(r=>[
      `${r.ref}`,r.name,bdg(r.state),
      r.estimated?r.estimated.toLocaleString()+' ج.م':'—',
      r.awarded?r.awarded.toLocaleString()+' ج.م':'—',r.supplier
    ]),
  }),
  permits: () => ({
    title:'📦 تفاصيل أذونات الإضافة',
    kpis:[{v:D.permits.total,l:'إجمالي'},{v:D.permits.posted,l:'مرحّل'},{v:D.permits.cancelled,l:'ملغي'}],
    headers:['المرجع','الصنف','الحالة','الكمية','المستودع','التاريخ'],
    rows:(D.permits.detail||[]).map(r=>[
      `${r.ref}`,
      r.name,bdg(r.state),r.qty,r.warehouse,r.date
    ]),
  }),
  custody: () => ({
    title:'🔑 تفاصيل العهد النشطة',
    kpis:[{v:D.custody.active,l:'نشطة'},{v:D.custody.overdue,l:'متأخرة'},{v:fmt(D.custody.total_value),l:'القيمة الكلية'}],
    headers:['المرجع','الموظف','الحالة','القيمة','تاريخ الاسترداد'],
    rows:(D.custody.detail||[]).map(r=>[
      `${r.ref}`,
      r.employee,bdg(r.state),
      r.value?r.value.toLocaleString()+' ج.م':'—',r.due
    ]),
  }),
  stocktaking: () => ({
    title:'📊 تفاصيل جلسات الجرد',
    kpis:[{v:D.stocktaking.total,l:'إجمالي'},{v:D.stocktaking.done,l:'بانتظار اعتماد'},{v:D.stocktaking.validated,l:'معتمد'}],
    headers:['الجلسة','المستودع','السنة المالية','الحالة','رئيس اللجنة'],
    rows:(D.stocktaking.detail||[]).map(r=>[
      `${r.name}`,
      r.warehouse,r.year,bdg(r.state),r.chairman
    ]),
  }),
  auctions: () => ({
    title:'🏛️ تفاصيل المزادات',
    kpis:[{v:D.auction.by_state.session_open+D.auction.by_state.bidding,l:'نشط'},{v:D.auction.by_state.done,l:'مكتمل'},{v:D.auction.lease.active,l:'عقد إيجار'}],
    headers:['المرجع','الاسم','النوع','الحالة','التقديري','الترسية'],
    rows:(D.auction.detail||[]).map(r=>[
      `${r.ref}`,
      r.name,r.type,bdg(r.state),
      r.estimated?r.estimated.toLocaleString()+' ج.م':'—',
      r.awarded?r.awarded.toLocaleString()+' ج.م':'—'
    ]),
  }),
};

function openDrill(key) {
  const fn = DRILLS[key];
  if(!fn) return;
  const info = fn();
  document.getElementById('drill-ttl').innerHTML = info.title;
  document.getElementById('drill-kpis').innerHTML = info.kpis.map(k=>
    `

${k.v}
${k.l}`
  ).join('');
  const tbody = info.rows.map(r=>`
${r.map(c=>`${c}`).join('')}`).join('');
  document.getElementById('drill-tbl').innerHTML =
    `
${info.headers.map(h=>`${h}`).join('')}${tbody}`;
  document.getElementById('drill-ov').classList.add('open');
}
function closeDrill() { document.getElementById('drill-ov').classList.remove('open'); }

// ── Boot ─────────────────────────────────────────────────────────
fetchData();
setInterval(fetchData, 300000); // refresh every 5 min
